import React from 'react';
import { useConversation } from './hooks/useConversation';
import InputArea from './components/InputArea';

function App() {
  const { messages, isTyping, currentStep, handleUserAnswer } = useConversation();
  const latestBotMessage = messages.filter(m => m.sender === 'bot').slice(-1)[0]?.text;

  return (
    <div className="h-screen w-screen flex flex-col items-center justify-between py-20 px-10">
      
      {/* 1. Header: Tiny and professional */}
      <div className="text-slate-400 uppercase tracking-[0.2em] text-[10px] font-bold">
        NIMHANS Clinical Protocol • Confidential
      </div>

      {/* 2. Main Question: Huge and Centered */}
      <div className="flex-1 flex items-center justify-center max-w-4xl w-full">
        {isTyping ? (
          <div className="flex gap-2">
            {[0, 1, 2].map(i => (
              <div key={i} className="w-2 h-2 bg-emerald-400 rounded-full animate-bounce" style={{animationDelay: `${i*0.2}s`}} />
            ))}
          </div>
        ) : (
          <h1 className="text-4xl md:text-6xl font-semibold text-slate-800 text-center leading-tight fade-in">
            {latestBotMessage}
          </h1>
        )}
      </div>

      {/* 3. Input: Bold and Modern */}
      <div className="w-full max-w-xl">
        <InputArea 
          currentStep={currentStep} 
          onSendMessage={handleUserAnswer} 
          isTyping={isTyping} 
        />
      </div>

      {/* 4. Progress bar at the very bottom */}
      <div className="fixed bottom-0 left-0 h-1 bg-emerald-500 transition-all duration-1000" 
           style={{ width: `${(messages.filter(m => m.sender === 'bot').length / 5) * 100}%` }} />
    </div>
  );
}

export default App;
